import React, { useState } from "react";
import { Box, Button, Container, TextField, Typography, Paper, Alert, CircularProgress } from "@mui/material";
import axios from "axios";

export default function Login() {
  const [mobile, setMobile] = useState("");
  const [otp, setOtp] = useState("");
  const [loading, setLoading] = useState(false);
  const [error, setError] = useState("");
  const [success, setSuccess] = useState("");
  const [showOtp, setShowOtp] = useState(false);

  // Step 1: Request OTP (simulate sending OTP)
  const handleRequestOtp = async () => {
    if (!/^[6-9]\d{9}$/.test(mobile)) { 
      setError("Enter valid mobile number"); 
      return; 
    }

    setLoading(true);
    setError("");
    setSuccess("");

    try {
      // Check if user exists
      const res = await axios.post("http://localhost:5000/api/auth/login", { mobile, otp: "123456" });

      if (res.data.success) {
        setShowOtp(true); // show OTP input
        setSuccess("OTP is 123456 for testing"); // inform user about OTP
      }
    } catch (err) {
      // If user not found
      if (err.response?.data?.message) {
        setError(err.response.data.message);
      } else {
        setError("Server error");
      }
    } finally {
      setLoading(false);
    }
  };

  // Step 2: Verify OTP
  const handleLogin = async () => {
    if (!otp) { setError("Enter OTP"); return; }

    setLoading(true);
    setError("");
    setSuccess("");

    try {
      const res = await axios.post("http://localhost:5000/api/auth/login", { mobile, otp });

      if (res.data.success) {
        setSuccess("Login successful");
        setError("");
        setShowOtp(false);
      } else {
        setError(res.data.message);
      }
    } catch (err) {
      setError(err.response?.data?.message || "Server error");
    } finally {
      setLoading(false);
    }
  };

  return (
    <Container maxWidth="sm">
      <Paper elevation={3} sx={{ p: 4, mt: 5, borderRadius: 3 }}>
        <Typography variant="h4" align="center" gutterBottom sx={{ color: "orangered" }}>Rider App</Typography>

        {error && <Alert severity="error" sx={{ mb: 2 }}>{error}</Alert>}
        {success && <Alert severity="success" sx={{ mb: 2 }}>{success}</Alert>}

        <Box sx={{ mt: 2 }}>
          <TextField
            fullWidth
            label="Mobile Number"
            value={mobile}
            onChange={(e) => setMobile(e.target.value)}
            margin="normal"
          />

          {showOtp && (
            <TextField
              fullWidth
              label="OTP"
              value={otp}
              onChange={(e) => setOtp(e.target.value)}
              margin="normal"
            />
          )}

          {!showOtp ? (
            <Button
              fullWidth
              variant="contained"
              sx={{ mt: 2, bgcolor: "orangered", "&:hover": { bgcolor: "darkred" } }}
              onClick={handleRequestOtp}
              disabled={loading}
            >
              {loading ? <CircularProgress size={24} sx={{ color: "white" }} /> : "Request OTP"}
            </Button>
          ) : (
            <Button
              fullWidth
              variant="contained"
              sx={{ mt: 2, bgcolor: "orangered", "&:hover": { bgcolor: "darkred" } }}
              onClick={handleLogin}
              disabled={loading}
            >
              {loading ? <CircularProgress size={24} sx={{ color: "white" }} /> : "Login"}
            </Button>
          )}
        </Box>
      </Paper>
    </Container>
  );
}
